#include<bits/stdc++.h>
using namespace std;
vector<int> a;
long long n, m, ans;
int main() {
	cin >> n >> m;
	for (int i = 1; i <= n; i++) {
		int x;
		cin>>x;
		a.push_back(x);
	}
	sort(a.begin(), a.end());

	for (auto i = a.begin(); i < a.end(); i++) {
		auto x = upper_bound(i, a .end(),*i+m);
		x--;
		ans += (x - i);

	}
	cout<<ans;
	return 0;
}
